import { Home, Target, CreditCard, User } from "lucide-react";

export default function BottomNav({ active, setActive }) {
  const tabs = [
    { id: "home", icon: Home, label: "Home" },
    { id: "goals", icon: Target, label: "Goals" },
    { id: "loans", icon: CreditCard, label: "Loans" },
    { id: "profile", icon: User, label: "Profile" },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex justify-around py-3 z-50">
      {tabs.map(({ id, icon: Icon, label }) => (
        <button
          key={id}
          onClick={() => setActive(id)}
          className={`flex flex-col items-center text-xs ${
            active === id ? "text-teal-600" : "text-gray-400"
          }`}
        >
          <Icon size={22} />
          {label}
        </button>
      ))}
    </div>
  );
}
